// Aceita { ioc: "..." }, { iocs: [...] } ou { ioc: [...] }
const body = $json.body ?? $json;
const rawIocs = Array.isArray(body.iocs)
  ? body.iocs
  : Array.isArray(body.ioc)
    ? body.ioc
    : body.ioc
      ? [body.ioc]
      : [];

function detectType(v) {
  const s = String(v || '').trim();
  if (!s) return 'unknown';
  if (/^(https?:\/\/)/i.test(s)) return 'url';
  if (/^((25[0-5]|2[0-4]\d|1?\d?\d)\.){3}(25[0-5]|2[0-4]\d|1?\d?\d)$/.test(s)) return 'ip';
  if (/^[a-fA-F0-9]{32}$/.test(s)) return 'md5';
  if (/^[a-fA-F0-9]{40}$/.test(s)) return 'sha1';
  if (/^[a-fA-F0-9]{64}$/.test(s)) return 'sha256';
  if (/^(?=.{1,253}$)(?!-)[A-Za-z0-9-]{1,63}(?<!-)(\.(?!-)[A-Za-z0-9-]{1,63}(?<!-))+$/i.test(s)) return 'domain';
  return 'unknown';
}

return rawIocs
  .filter(Boolean)
  .map(v => ({
    json: {
      ioc: String(v).trim(),
      type: detectType(String(v).trim()),
      source: body.source || 'webhook'
    }
  }));

const ioc = $json.ioc || 'N/A';
const type = $json.type || 'unknown';
console.warn(`[IOC Skip] Tipo não suportado: "${type}" para IoC "${ioc}"`);
return [{ json: { skipped: true, ioc, type, reason: 'unsupported_type' } }];

const result = $input.first().json;
let output = '==============================\n';
output += `IOC REPORT — AlienVault OTX\n`;
output += `Indicator: ${result.indicator || 'N/A'}\n`;
output += `Type: ${result.type || 'N/A'}\n`;
output += `Country: ${result.country_name || result.country_code || 'N/A'}\n`;
output += `ASN: ${result.asn || 'N/A'}\n`;
output += `Reputation: ${result.reputation ?? 'N/A'}\n`;
output += `Pulse count: ${result.pulse_info?.count || 0}\n\n`;
const pulses = result.pulse_info?.pulses || [];
if (pulses.length === 0) {
  output += 'Nenhum pulse encontrado.\n';
} else {
  pulses.slice(0, 10).forEach((pulse, i) => {
    output += `--- Pulse ${i + 1} ---\n`;
    output += `Name: ${pulse.name || 'N/A'}\n`;
    output += `Description: ${(pulse.description || 'N/A').substring(0, 300)}\n`;
    output += `Tags: ${(pulse.tags || []).join(', ') || 'N/A'}\n`;
    output += `Malware families: ${(pulse.malware_families || []).map(m => m.display_name || m.id).join(', ') || 'N/A'}\n`;
    output += `Attack IDs (MITRE): ${(pulse.attack_ids || []).map(a => a.display_name || a.id).join(', ') || 'N/A'}\n`;
    output += `TLP: ${pulse.TLP || 'N/A'}\n`;
    output += `----------------------\n`;
  });
}
output += '==============================\n';
return [{ json: { text: output.trim(), source: 'alienvault', ioc: result.indicator } }];

const raw = $input.first().json;
const attrs = raw.data?.attributes || {};
const ioc = $('Normalize IOC').item.json.ioc;
const type = $('Normalize IOC').item.json.type;
const stats = attrs.last_analysis_stats || {};
const malicious = stats.malicious || 0;
const suspicious = stats.suspicious || 0;
const total = Object.values(stats).reduce((a, b) => a + b, 0);
let topEngines = [];
if (attrs.last_analysis_results) {
  topEngines = Object.entries(attrs.last_analysis_results)
    .filter(([, r]) => r.category === 'malicious' || r.category === 'suspicious')
    .map(([engine, r]) => `${engine}: ${r.result || r.category}`)
    .slice(0, 10);
}
const reputation = attrs.reputation ?? 'N/A';
const categories = attrs.categories ? Object.values(attrs.categories).join(', ') : 'N/A';
const names = (attrs.names || []).slice(0, 5).join(', ') || 'N/A';
const typeDesc = attrs.type_description || 'N/A';
let output = '==============================\n';
output += `IOC REPORT — VirusTotal\n`;
output += `IOC: ${ioc}\nType: ${type}\n`;
output += `Malicious: ${malicious}/${total}\n`;
output += `Suspicious: ${suspicious}/${total}\n`;
output += `Reputation: ${reputation}\n`;
if (type === 'ip' || type === 'domain') output += `Categories: ${categories}\n`;
if (type === 'md5' || type === 'sha1' || type === 'sha256') {
  output += `Type description: ${typeDesc}\n`;
  output += `Known names: ${names}\n`;
}
if (topEngines.length > 0) {
  output += `\nDetections:\n`;
  topEngines.forEach(e => { output += `  ${e}\n`; });
}
output += '==============================\n';
return [{ json: { text: output.trim(), source: 'virustotal', ioc } }];

// Constrói a query GraphQL para o OpenCTI baseada no tipo de IoC
// O OpenCTI usa a API GraphQL em /graphql
// Pesquisamos stixCyberObservables por valor
const ioc = $('Normalize IOC').item.json.ioc;
const type = $('Normalize IOC').item.json.type;

// Mapeia tipo local para tipo STIX/OpenCTI
const typeMap = {
  ip:     'IPv4-Addr',
  domain: 'Domain-Name',
  url:    'Url',
  md5:    'StixFile',
  sha1:   'StixFile',
  sha256: 'StixFile'
};
const stixType = typeMap[type] || null;

// Query GraphQL — busca o observable e as suas relações
const query = `
  query SearchAllIoC {
  stixCyberObservables(
    search: "` + ioc +  `" 
    first: 25 
  ) {
    edges {
      node {
        id
        entity_type
        observable_value
        created_at
        updated_at
        x_opencti_score
        x_opencti_description
        indicators {
          edges {
            node {
              id
              name
              pattern
              valid_from
              valid_until
            }
          }
        }
      }
    }
    pageInfo {
      hasNextPage
      endCursor
      globalCount
    }
  }
}
`;

return [{ json: { query, variables: { value: ioc }, ioc, type } }];

// Parse da resposta GraphQL do OpenCTI
const raw = $input.first().json;
const ioc = $('OpenCTI — Build Query').item.json.ioc;
const edges = raw?.data?.stixCyberObservables?.edges || [];

if (edges.length === 0) {
  return [{ json: {
    text: `==============================\nIOC REPORT — OpenCTI\nIndicator: ${ioc}\nResultado: Nenhum observable encontrado na plataforma OpenCTI.\n==============================`,
    source: 'opencti',
    ioc
  }}];
}

let output = '==============================\n';
output += `IOC REPORT — OpenCTI\n`;
output += `Indicator: ${ioc}\n\n`;

for (const edge of edges) {
  const node = edge.node;
  output += `Entity type: ${node.entity_type || 'N/A'}\n`;
  output += `Value: ${node.observable_value || 'N/A'}\n`;
  output += `Created by: ${node.createdBy?.name || 'N/A'}\n`;
  const tlps = (node.objectMarking || []).map(m => m.definition).join(', ') || 'N/A';
  output += `TLP: ${tlps}\n\n`;

  // Relatórios associados
  const reports = node.reports?.edges || [];
  if (reports.length > 0) {
    output += `Relatórios associados (${reports.length}):\n`;
    reports.forEach(r => {
      const rn = r.node;
      output += `  - ${rn.name || 'N/A'} (publicado: ${rn.published || 'N/A'}, confiança: ${rn.confidence ?? 'N/A'})\n`;
      if (rn.description) output += `    ${rn.description.substring(0, 200)}\n`;
    });
    output += '\n';
  }

  // Indicadores STIX
  const indicators = node.indicators?.edges || [];
  if (indicators.length > 0) {
    output += `Indicadores STIX (${indicators.length}):\n`;
    indicators.forEach(i => {
      const ind = i.node;
      output += `  - ${ind.name || 'N/A'} | válido: ${ind.valid_from || '?'} → ${ind.valid_until || '?'} | confiança: ${ind.confidence ?? 'N/A'}\n`;
    });
    output += '\n';
  }

  // Relações (Threat Actors, Campanhas, Malware, ATT&CK)
  const rels = node.stixRelationships?.edges || [];
  const threatActors = [];
  const intrusionSets = [];
  const campaigns = [];
  const malwares = [];
  const attackPatterns = [];

  for (const rel of rels) {
    const to = rel.node?.to;
    if (!to) continue;
    const rt = rel.node.relationship_type;
    if (to.malware_types !== undefined) malwares.push(`${to.name} (${(to.malware_types || []).join(', ') || 'N/A'})`);
    else if (to.x_mitre_id !== undefined) attackPatterns.push(`${to.x_mitre_id}: ${to.name}`);
    else if (to.first_seen !== undefined) campaigns.push(`${to.name} (${to.first_seen || '?'} → ${to.last_seen || '?'})`);
    else if (to.aliases !== undefined && rt !== 'related-to') intrusionSets.push(`${to.name} (${(to.aliases || []).join(', ') || 'sem aliases'})`);
    else if (to.aliases !== undefined) threatActors.push(`${to.name} (${(to.aliases || []).join(', ') || 'sem aliases'})`);
  }

  if (threatActors.length)   output += `Threat Actors:\n  - ${threatActors.join('\n  - ')}\n\n`;
  if (intrusionSets.length)  output += `Intrusion Sets (APT):\n  - ${intrusionSets.join('\n  - ')}\n\n`;
  if (campaigns.length)      output += `Campanhas:\n  - ${campaigns.join('\n  - ')}\n\n`;
  if (malwares.length)       output += `Malware:\n  - ${malwares.join('\n  - ')}\n\n`;
  if (attackPatterns.length) output += `MITRE ATT&CK Patterns:\n  - ${attackPatterns.join('\n  - ')}\n\n`;

  output += '------------------------------\n';
}

output += '==============================\n';
return [{ json: { text: output.trim(), source: 'opencti', ioc } }];

// Combina AlienVault + VirusTotal + OpenCTI num único objecto para o Gemini
const allItems = $input.all();
const result = {
  ioc: null,
  type: null,
  alienvault: null,
  virustotal: null,
  opencti: null
};

for (const item of allItems) {
  const d = item.json;
  if (!result.ioc && d.ioc) result.ioc = d.ioc;
  if (!result.type) {
    try { result.type = $('Normalize IOC').first()?.json?.type || 'unknown'; } catch(e) {}
  }
  if (d.source === 'alienvault') result.alienvault = d;
  if (d.source === 'virustotal') result.virustotal = d;
  if (d.source === 'opencti')    result.opencti = d;
}

return [{ json: result }];
